{
  "name": "MediSim: ER CME Simulator",
  "description": "An interactive clinical case simulator that generates complex, high-stakes ER scenarios based on uploaded CME PDF documents. Features dynamic vital signs, generated radiology/EKG images, and AI-driven patient responses."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Vitals {
  hr: number;
  bpSystolic: number;
  bpDiastolic: number;
  rr: number;
  o2: number;
  temp: number;
  rhythm: string;
}

export interface Message {
  role: 'user' | 'assistant' | 'system';
  content: string;
  type?: 'text' | 'image' | 'alert' | 'success';
  timestamp: number;
  imageData?: string; // Base64 image data
}

export interface GameState {
  stage: 'upload' | 'analyzing' | 'playing' | 'debrief';
  vitals: Vitals;
  messages: Message[];
  learningPoints: string[];
  hiddenDiagnosis: string;
  caseContext: string; // The summarized context from the PDF
}

export interface ActionPayload {
  actionType: 'history' | 'exam' | 'labs' | 'imaging' | 'treatment' | 'consult';
  detail: string;
}

export interface SimulationResponse {
  narrative: string;
  updatedVitals: Vitals;
  visualRequest?: {
    type: 'EKG' | 'CXR' | 'CT' | 'Skin';
    description: string;
  };
  isCaseOver: boolean;
  debrief?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Vitals, SimulationResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using the recommended models from the guide
const TEXT_MODEL = "gemini-3-pro-preview"; 
const IMAGE_MODEL = "gemini-3-pro-image-preview";

export const analyzePDFAndStartCase = async (
  pdfBase64: string
): Promise<{ 
  intro: string; 
  vitals: Vitals; 
  context: string; 
  learningPoints: string[]; 
  diagnosis: string 
}> => {
  const prompt = `
    You are a senior Emergency Medicine Attending and Clinical Educator.

    TASK:
    1. Analyze the attached CME (Continuing Medical Education) PDF document.
    2. Identify the core clinical topic, critical pitfalls, and major learning points.
    3. Generate a HIGH-STAKES, COMPLEX clinical simulation case based on this document.
    4. The case should start with a patient presentation in the ER.

    OUTPUT FORMAT (JSON):
    {
      "intro": "The initial scene description and patient presentation (Chief Complaint, appearance).",
      "vitals": {
        "hr": 90, "bpSystolic": 120, "bpDiastolic": 80, "rr": 16, "o2": 98, "temp": 37.0, "rhythm": "Sinus Rhythm"
      },
      "context": "A summary of the case logic and how it relates to the PDF (for internal logic).",
      "learningPoints": ["Point 1", "Point 2"],
      "diagnosis": "The final diagnosis based on the PDF content."
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: TEXT_MODEL,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "application/pdf",
              data: pdfBase64,
            },
          },
          { text: prompt },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            intro: { type: Type.STRING },
            vitals: {
              type: Type.OBJECT,
              properties: {
                hr: { type: Type.NUMBER },
                bpSystolic: { type: Type.NUMBER },
                bpDiastolic: { type: Type.NUMBER },
                rr: { type: Type.NUMBER },
                o2: { type: Type.NUMBER },
                temp: { type: Type.NUMBER },
                rhythm: { type: Type.STRING },
              },
              required: ["hr", "bpSystolic", "bpDiastolic", "rr", "o2", "temp", "rhythm"],
            },
            context: { type: Type.STRING },
            learningPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
            diagnosis: { type: Type.STRING },
          },
        },
      },
    });

    if (!response.text) throw new Error("No response from Gemini");
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Error starting case:", error);
    throw error;
  }
};

export const progressSimulation = async (
  context: string,
  history: string[],
  userAction: string
): Promise<SimulationResponse> => {
  const prompt = `
    You are the simulation engine for an ER case.

    CASE CONTEXT: ${context}

    HISTORY:
    ${history.join("\n")}

    USER ACTION: ${userAction}

    INSTRUCTIONS:
    1. React to the user's action realistically. Time moves forward.
    2. If the user orders a relevant test (EKG, CXR) that shows the pathology described in the context, request a visual generation.
    3. Update vital signs based on the patient's trajectory (deteriorating or improving).
    4. If the user makes a critical mistake (pitfall from the PDF), the patient should deteriorate.
    5. If the case is concluded (patient stabilized, diagnosis confirmed, or patient expired), set isCaseOver to true and provide a debrief.

    OUTPUT FORMAT (JSON):
    {
      "narrative": "The result of the action and current patient status.",
      "updatedVitals": { ... },
      "visualRequest": { "type": "EKG", "description": "Visual description for image generator" } (OPTIONAL, only if user ordered imaging AND it is relevant to show),
      "isCaseOver": boolean,
      "debrief": "Summary of performance if case is over, else null"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: TEXT_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
         responseSchema: {
          type: Type.OBJECT,
          properties: {
            narrative: { type: Type.STRING },
            updatedVitals: {
              type: Type.OBJECT,
              properties: {
                hr: { type: Type.NUMBER },
                bpSystolic: { type: Type.NUMBER },
                bpDiastolic: { type: Type.NUMBER },
                rr: { type: Type.NUMBER },
                o2: { type: Type.NUMBER },
                temp: { type: Type.NUMBER },
                rhythm: { type: Type.STRING },
              },
               required: ["hr", "bpSystolic", "bpDiastolic", "rr", "o2", "temp", "rhythm"],
            },
            visualRequest: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, enum: ["EKG", "CXR", "CT", "Skin"] },
                description: { type: Type.STRING },
              },
            },
            isCaseOver: { type: Type.BOOLEAN },
            debrief: { type: Type.STRING },
          },
        },
      },
    });

    if (!response.text) throw new Error("No simulation response");
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Error progressing simulation:", error);
    throw error;
  }
};

export const generateMedicalImage = async (description: string, type: string): Promise<string> => {
  const prompt = `Create a realistic, high-quality medical image of a ${type}. Clinical details: ${description}. The image should be suitable for medical education. No text overlays.`;

  try {
    // Check if we need to use a specific model or if generateContent supports images well enough.
    // The instructions say use 'gemini-3-pro-image-preview' for high quality.

    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
            aspectRatio: "4:3",
            imageSize: "1K"
        }
      }
    });

    // Extract image
    // The SDK guidance says: iterate through parts to find inlineData.
    if (response.candidates && response.candidates[0].content.parts) {
        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return part.inlineData.data;
            }
        }
    }

    throw new Error("No image data found in response");

  } catch (error) {
    console.error("Error generating image:", error);
    // Return a placeholder or empty string if generation fails to avoid crashing app
    return "";
  }
};

import React from 'react';
import { Vitals } from '../types';

interface Props {
  vitals: Vitals;
}

const VitalBox = ({ label, value, unit, color, flicker = false }: { label: string, value: string | number, unit?: string, color: string, flicker?: boolean }) => (
  <div className={`flex flex-col items-start justify-between bg-black/40 border border-slate-800 p-2 rounded w-full ${flicker ? 'animate-pulse' : ''}`}>
    <span className={`text-xs font-bold ${color} opacity-70`}>{label}</span>
    <div className="flex items-end gap-1">
      <span className={`text-3xl font-bold monitor-font ${color} leading-none`}>{value}</span>
      {unit && <span className="text-xs text-slate-500 mb-1">{unit}</span>}
    </div>
  </div>
);

const VitalsMonitor: React.FC<Props> = ({ vitals }) => {
  // Determine color based on stability (basic logic)
  const hrColor = vitals.hr > 120 || vitals.hr < 50 ? 'text-red-500' : 'text-green-500';
  const o2Color = vitals.o2 < 92 ? 'text-red-500' : 'text-blue-500';
  const bpColor = vitals.bpSystolic < 90 ? 'text-red-500' : 'text-yellow-500';

  return (
    <div className="bg-slate-900/90 border-b border-slate-700 p-3 shadow-lg sticky top-0 z-20 backdrop-blur-md">
      <div className="max-w-4xl mx-auto">
        <div className="flex items-center justify-between mb-2">
           <h2 className="text-xs uppercase tracking-widest text-slate-400 font-semibold">Patient Monitor</h2>
           <span className="text-xs text-emerald-500 font-mono animate-pulse">LIVE DATA</span>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-5 gap-2">
          <VitalBox label="HR" value={vitals.hr} unit="bpm" color={hrColor} />
          <VitalBox label="NIBP" value={`${vitals.bpSystolic}/${vitals.bpDiastolic}`} unit="mmHg" color={bpColor} />
          <VitalBox label="SpO2" value={vitals.o2} unit="%" color={o2Color} />
          <VitalBox label="RR" value={vitals.rr} unit="rpm" color="text-cyan-400" />
          <VitalBox label="TEMP" value={vitals.temp} unit="°C" color="text-orange-400" />
        </div>

        <div className="mt-2 text-right">
             <span className={`text-xs font-mono font-bold tracking-wider uppercase ${hrColor}`}>
                {vitals.rhythm}
             </span>
        </div>
      </div>
    </div>
  );
};

export default VitalsMonitor;

import React, { useEffect, useRef } from 'react';
import { Message } from '../types';

interface Props {
  messages: Message[];
  isLoading: boolean;
}

const ChatInterface: React.FC<Props> = ({ messages, isLoading }) => {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  return (
    <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-950/50 min-h-[400px]">
      {messages.map((msg, idx) => (
        <div
          key={idx}
          className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
        >
          <div
            className={`max-w-[85%] md:max-w-[70%] rounded-lg p-4 shadow-md ${
              msg.role === 'user'
                ? 'bg-blue-900/30 text-blue-100 border border-blue-800'
                : msg.type === 'alert'
                ? 'bg-red-900/20 text-red-200 border border-red-800'
                : 'bg-slate-800 text-slate-200 border border-slate-700'
            }`}
          >
            {msg.role === 'assistant' && (
              <div className="text-xs text-slate-500 font-bold mb-1 uppercase tracking-wide">
                {msg.type === 'alert' ? 'CRITICAL UPDATE' : 'System'}
              </div>
            )}

            <p className="whitespace-pre-wrap leading-relaxed text-sm md:text-base">
              {msg.content}
            </p>

            {msg.imageData && (
              <div className="mt-3 rounded overflow-hidden border border-slate-600 bg-black">
                <img 
                  src={`data:image/png;base64,${msg.imageData}`} 
                  alt="Medical Imaging" 
                  className="w-full h-auto object-contain max-h-96"
                />
                <div className="text-xs text-center text-slate-500 py-1 bg-slate-900">
                    AI Generated Clinical Image
                </div>
              </div>
            )}

            <div className="text-[10px] text-slate-500 mt-2 text-right">
                {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
            </div>
          </div>
        </div>
      ))}

      {isLoading && (
        <div className="flex justify-start">
          <div className="bg-slate-800/50 rounded-lg p-3 flex items-center gap-2 border border-slate-700">
            <div className="w-2 h-2 bg-emerald-500 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
            <div className="w-2 h-2 bg-emerald-500 rounded-full animate-bounce" style={{ animationDelay: '0.15s' }}></div>
            <div className="w-2 h-2 bg-emerald-500 rounded-full animate-bounce" style={{ animationDelay: '0.3s' }}></div>
            <span className="text-xs text-emerald-500 ml-1 font-mono">PROCESSING</span>
          </div>
        </div>
      )}
      <div ref={bottomRef} />
    </div>
  );
};

export default ChatInterface;

import React, { useState } from 'react';

interface Props {
  onAction: (action: string) => void;
  disabled: boolean;
}

const CATEGORIES = [
  { id: 'history', label: 'History', icon: '📋' },
  { id: 'exam', label: 'Physical Exam', icon: '🩺' },
  { id: 'orders', label: 'Orders/Labs', icon: '🧪' },
  { id: 'imaging', label: 'Imaging', icon: '☢️' },
  { id: 'treatment', label: 'Treatment', icon: '💊' },
  { id: 'consult', label: 'Consult', icon: '☎️' },
];

const Controls: React.FC<Props> = ({ onAction, disabled }) => {
  const [activeCategory, setActiveCategory] = useState<string | null>(null);
  const [inputText, setInputText] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const prefix = activeCategory ? `[${CATEGORIES.find(c => c.id === activeCategory)?.label}] ` : '';
    onAction(`${prefix}${inputText}`);
    setInputText('');
    setActiveCategory(null);
  };

  return (
    <div className="bg-slate-900 border-t border-slate-700 p-4">
      <div className="max-w-4xl mx-auto space-y-3">
        {/* Category Toggles */}
        <div className="flex flex-wrap gap-2 justify-center md:justify-start">
          {CATEGORIES.map((cat) => (
            <button
              key={cat.id}
              onClick={() => setActiveCategory(activeCategory === cat.id ? null : cat.id)}
              disabled={disabled}
              className={`px-3 py-1.5 rounded-full text-xs font-semibold flex items-center gap-1.5 transition-all
                ${activeCategory === cat.id 
                  ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/50' 
                  : 'bg-slate-800 text-slate-300 hover:bg-slate-700 border border-slate-700'
                }
                ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
              `}
            >
              <span>{cat.icon}</span>
              {cat.label}
            </button>
          ))}
        </div>

        {/* Input Field */}
        <form onSubmit={handleSubmit} className="relative">
          <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 font-mono text-sm">
            {activeCategory ? '>' : ''}
          </div>
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            disabled={disabled}
            placeholder={
                disabled ? 'Wait for response...' :
                activeCategory 
                ? `Enter ${CATEGORIES.find(c => c.id === activeCategory)?.label} details...` 
                : "Type an action or choose a category..."
            }
            className={`w-full bg-slate-950 text-slate-100 rounded-lg pl-8 pr-12 py-3 border focus:outline-none focus:ring-1 transition-colors font-mono
                ${disabled ? 'border-slate-800 text-slate-500' : 'border-slate-700 focus:border-emerald-500 placeholder-slate-600'}
            `}
          />
          <button
            type="submit"
            disabled={disabled || !inputText.trim()}
            className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 rounded-md bg-emerald-600 text-white disabled:opacity-0 disabled:scale-95 transition-all hover:bg-emerald-500"
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
              <path d="M3.105 2.289a.75.75 0 00-.826.95l1.414 4.925A1.5 1.5 0 005.135 9.25h6.115a.75.75 0 010 1.5H5.135a1.5 1.5 0 00-1.442 1.085l-1.414 4.926a.75.75 0 00.826.95 14 14 0 007-7 14 14 0 00-7-7z" />
            </svg>
          </button>
        </form>
      </div>
    </div>
  );
};

export default Controls;

import React, { useState, useRef } from 'react';
import { GameState, Message } from './types';
import { analyzePDFAndStartCase, progressSimulation, generateMedicalImage } from './services/geminiService';
import VitalsMonitor from './components/VitalsMonitor';
import ChatInterface from './components/ChatInterface';
import Controls from './components/Controls';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    stage: 'upload',
    vitals: { hr: 0, bpSystolic: 0, bpDiastolic: 0, rr: 0, o2: 0, temp: 0, rhythm: '--' },
    messages: [],
    learningPoints: [],
    hiddenDiagnosis: '',
    caseContext: '',
  });

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      setError("Please upload a PDF file.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setGameState(prev => ({ ...prev, stage: 'analyzing' }));

    try {
      // Convert to Base64
      const reader = new FileReader();
      reader.onload = async (e) => {
        const base64Data = (e.target?.result as string).split(',')[1];

        try {
          const initData = await analyzePDFAndStartCase(base64Data);

          setGameState({
            stage: 'playing',
            vitals: initData.vitals,
            messages: [{
              role: 'assistant',
              content: initData.intro,
              timestamp: Date.now()
            }],
            learningPoints: initData.learningPoints,
            hiddenDiagnosis: initData.diagnosis,
            caseContext: initData.context
          });
        } catch (err) {
          setError("Failed to analyze PDF using AI. Please try again or check API Key quota.");
          setGameState(prev => ({ ...prev, stage: 'upload' }));
        } finally {
            setIsLoading(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError("Error reading file.");
      setIsLoading(false);
      setGameState(prev => ({ ...prev, stage: 'upload' }));
    }
  };

  const handleUserAction = async (actionText: string) => {
    // Add user message immediately
    const userMsg: Message = { role: 'user', content: actionText, timestamp: Date.now() };
    setGameState(prev => ({
      ...prev,
      messages: [...prev.messages, userMsg]
    }));
    setIsLoading(true);

    try {
      // Construct history for context
      const history = gameState.messages.map(m => `${m.role.toUpperCase()}: ${m.content}`);

      const response = await progressSimulation(
        gameState.caseContext,
        history,
        actionText
      );

      const newMessages: Message[] = [];
      let imageData = undefined;

      // Handle Image Generation if requested
      if (response.visualRequest) {
        // Add a placeholder message first or just attach image to result
        try {
             const base64Img = await generateMedicalImage(response.visualRequest.description, response.visualRequest.type);
             if (base64Img) imageData = base64Img;
        } catch (imgErr) {
            console.error("Image gen failed", imgErr);
        }
      }

      // Add System Response
      newMessages.push({
        role: 'assistant',
        content: response.narrative,
        timestamp: Date.now(),
        type: response.updatedVitals.hr < 50 || response.updatedVitals.hr > 140 ? 'alert' : 'text',
        imageData
      });

      // Handle Game Over
      if (response.isCaseOver && response.debrief) {
        newMessages.push({
          role: 'assistant',
          content: `🛑 **CASE ENDED**\n\n${response.debrief}\n\n**Key Learning Points:**\n${gameState.learningPoints.map(p => `- ${p}`).join('\n')}`,
          timestamp: Date.now() + 100,
          type: 'success'
        });
        setGameState(prev => ({ ...prev, stage: 'debrief' }));
      }

      setGameState(prev => ({
        ...prev,
        vitals: response.updatedVitals,
        messages: [...prev.messages, ...newMessages]
      }));

    } catch (err) {
      console.error(err);
      const errorMsg: Message = { role: 'system', content: "Simulation Logic Error. Please try again.", timestamp: Date.now(), type: 'alert' };
      setGameState(prev => ({ ...prev, messages: [...prev.messages, errorMsg] }));
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="h-screen flex flex-col bg-slate-900 text-slate-200 overflow-hidden">

      {/* Header */}
      <header className="p-4 bg-slate-950 border-b border-slate-800 flex justify-between items-center z-10">
        <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-emerald-600 rounded flex items-center justify-center font-bold text-white shadow-lg shadow-emerald-500/20">M</div>
            <h1 className="text-xl font-bold tracking-tight text-slate-100">MediSim <span className="text-slate-500 font-normal">| ER AI</span></h1>
        </div>
        {gameState.stage !== 'upload' && (
             <button 
             onClick={() => window.location.reload()}
             className="text-xs text-slate-400 hover:text-white underline"
           >
             New Case
           </button>
        )}
      </header>

      {/* Main Content Area */}
      {gameState.stage === 'upload' || gameState.stage === 'analyzing' ? (
        <div className="flex-1 flex flex-col items-center justify-center p-6 text-center animate-fadeIn">
          <div className="max-w-md w-full bg-slate-800/50 p-8 rounded-2xl border border-slate-700 shadow-2xl backdrop-blur-sm">
            <div className="mb-6">
                <span className="text-6xl">🩺</span>
            </div>
            <h2 className="text-2xl font-bold text-white mb-2">Upload CME Material</h2>
            <p className="text-slate-400 mb-8">Upload a PDF clinical guideline or article. The AI will generate a complex simulation based on its content.</p>

            {gameState.stage === 'analyzing' ? (
                 <div className="flex flex-col items-center gap-4">
                    <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-emerald-400 font-mono text-sm animate-pulse">Analyzing Clinical Data...</p>
                 </div>
            ) : (
                <div className="relative group cursor-pointer">
                    <input 
                        type="file" 
                        ref={fileInputRef}
                        accept="application/pdf"
                        onChange={handleFileUpload}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                    />
                    <div className="border-2 border-dashed border-slate-600 rounded-xl p-6 group-hover:border-emerald-500 group-hover:bg-slate-700/50 transition-all">
                        <span className="text-emerald-500 font-semibold group-hover:underline">Click to browse</span> or drop PDF here
                    </div>
                </div>
            )}

            {error && (
                <div className="mt-4 p-3 bg-red-900/30 border border-red-800 rounded text-red-200 text-sm">
                    {error}
                </div>
            )}
          </div>
        </div>
      ) : (
        /* Simulation Interface */
        <div className="flex-1 flex flex-col overflow-hidden relative">
            <VitalsMonitor vitals={gameState.vitals} />

            <div className="flex-1 overflow-hidden relative flex flex-col">
                <ChatInterface messages={gameState.messages} isLoading={isLoading} />
            </div>

            <Controls 
                onAction={handleUserAction} 
                disabled={isLoading || gameState.stage === 'debrief'} 
            />
        </div>
      )}
    </div>
  );
};

export default App;

export interface Vitals {
  hr: number;
  bpSystolic: number;
  bpDiastolic: number;
  rr: number;
  o2: number;
