         "outcome": "Brief outcome description (e.g. Patient Stabilized)",
         "score": 0-100 (integer),
         "summary": "Detailed performance summary",
         "criticalEvents": [
            { "event": "Description of event", "userAction": "What user did", "optimalAction": "What user should have done", "feedback": "Explanation" }
         ],
         "missedOpportunities": ["Missed lab", "Missed diagnosis", etc],
         "cmeLearningPoints": ["Key takeaway from PDF"]
      } (OPTIONAL - only if isCaseOver is true)
