import { GoogleGenAI, Type } from "@google/genai";
import { Vitals, SimulationResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using the recommended models from the guide
const TEXT_MODEL = "gemini-3-pro-preview"; 
const IMAGE_MODEL = "gemini-3-pro-image-preview";

export const analyzePDFAndStartCase = async (
  pdfBase64: string
): Promise<{ 
  intro: string; 
  vitals: Vitals; 
  context: string; 
  learningPoints: string[]; 
  diagnosis: string 
}> => {
  const prompt = `
    You are a senior Emergency Medicine Attending and Clinical Educator.

    TASK:
    1. Analyze the attached CME (Continuing Medical Education) PDF document.
    2. Identify the core clinical topic, critical pitfalls, and major learning points.
    3. Generate a HIGH-STAKES, COMPLEX clinical simulation case based on this document.
    4. The case should start with a patient presentation in the ER.

    CRITICAL CONSTRAINT:
    - The 'context' field MUST be a concise summary (max 200 words) of the clinical logic.
    - Do NOT reproduce large sections of the PDF text in the output.
    - Ensure valid JSON output.

    OUTPUT FORMAT (JSON):
    {
      "intro": "The initial scene description and patient presentation (Chief Complaint, appearance).",
      "vitals": {
        "hr": 90, "bpSystolic": 120, "bpDiastolic": 80, "rr": 16, "o2": 98, "temp": 37.0, "rhythm": "Sinus Rhythm"
      },
      "context": "A concise summary of the case logic and how it relates to the PDF.",
      "learningPoints": ["Point 1", "Point 2"],
      "diagnosis": "The final diagnosis based on the PDF content."
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: TEXT_MODEL,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "application/pdf",
              data: pdfBase64,
            },
          },
          { text: prompt },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            intro: { type: Type.STRING },
            vitals: {
              type: Type.OBJECT,
              properties: {
                hr: { type: Type.NUMBER },
                bpSystolic: { type: Type.NUMBER },
                bpDiastolic: { type: Type.NUMBER },
                rr: { type: Type.NUMBER },
                o2: { type: Type.NUMBER },
                temp: { type: Type.NUMBER },
                rhythm: { type: Type.STRING },
              },
              required: ["hr", "bpSystolic", "bpDiastolic", "rr", "o2", "temp", "rhythm"],
            },
            context: { 
                type: Type.STRING,
                description: "Concise summary of case logic (max 200 words)" 
            },
            learningPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
            diagnosis: { type: Type.STRING },
          },
        },
      },
    });

    if (!response.text) throw new Error("No response from Gemini");

    let cleanText = response.text.trim();
    // Remove markdown code blocks if present (common cause of JSON parse errors if model adds them despite MIME type)
    if (cleanText.startsWith("```")) {
        cleanText = cleanText.replace(/^```(json)?/, "").replace(/```$/, "").trim();
    }

    return JSON.parse(cleanText);
  } catch (error) {
    console.error("Error starting case:", error);
    throw error;
  }
};

export const progressSimulation = async (
