): Promise<SimulationResponse> => {
  const prompt = `
    You are the simulation engine for an ER case based on a CME document.

    CASE CONTEXT: ${context}

    HISTORY:
    ${history.join("\n")}

    USER ACTION: ${userAction}

    INSTRUCTIONS:
    1. React to the user's action realistically. Time moves forward.
    2. If the user orders a relevant test (EKG, CXR) that shows the pathology described in the context, request a visual generation.
    3. Update vital signs based on the patient's trajectory (deteriorating or improving).
    4. If the user makes a critical mistake (pitfall from the PDF), the patient should deteriorate.
    5. If the case is concluded (patient stabilized, diagnosis confirmed, or patient expired), set isCaseOver to true and populate debriefData.

    DEBRIEF INSTRUCTIONS (Only if isCaseOver is true):
    - Generate a rigorous, detailed assessment.
    - Compare user actions directly to the "Optimal Management" defined in the CME PDF.
    - breakdown the score into categories.
    - For 'criticalEvents', categorize each as 'positive' (user did well), 'negative' (user made a mistake), or 'neutral'.

    OUTPUT FORMAT (JSON):
    {
      "narrative": "The result of the action and current patient status.",
      "updatedVitals": { ... },
      "visualRequest": { "type": "EKG", "description": "Visual description for image generator" } (OPTIONAL),
      "isCaseOver": boolean,
      "debriefData": {
         "outcome": "Brief outcome description",
         "score": 0-100 (integer),
         "summary": "Detailed performance summary",
         "performanceBreakdown": {
            "historyDataCollection": 0-100,
            "differentialDiagnosis": 0-100,
            "medicalManagement": 0-100,
            "communicationEfficiency": 0-100
         },
         "criticalEvents": [
            { 
              "event": "Description of decision point", 
              "userAction": "What user did", 
              "optimalAction": "What user should have done", 
              "feedback": "Deep clinical feedback referencing the CME content",
              "type": "positive" | "negative" | "neutral"
            }
         ],
         "missedOpportunities": ["Missed lab", "Missed diagnosis", etc],
         "cmeLearningPoints": ["Key takeaway from PDF"]
      } (OPTIONAL - only if isCaseOver is true)
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: TEXT_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
         responseSchema: {
          type: Type.OBJECT,
          properties: {
