            },
            visualRequest: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, enum: ["EKG", "CXR", "CT", "Skin"] },
                description: { type: Type.STRING },
              },
            },
            isCaseOver: { type: Type.BOOLEAN },
            debriefData: {
              type: Type.OBJECT,
              properties: {
                outcome: { type: Type.STRING },
                score: { type: Type.INTEGER },
                summary: { type: Type.STRING },
                performanceBreakdown: {
                    type: Type.OBJECT,
                    properties: {
                        historyDataCollection: { type: Type.INTEGER },
                        differentialDiagnosis: { type: Type.INTEGER },
                        medicalManagement: { type: Type.INTEGER },
                        communicationEfficiency: { type: Type.INTEGER },
                    },
                    required: ["historyDataCollection", "differentialDiagnosis", "medicalManagement", "communicationEfficiency"]
                },
                criticalEvents: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      event: { type: Type.STRING },
                      userAction: { type: Type.STRING },
                      optimalAction: { type: Type.STRING },
