const VitalsMonitor: React.FC<Props> = ({ vitals }) => {
  const [liveVitals, setLiveVitals] = useState<Vitals>(vitals);
  const lastPropsVitals = useRef<Vitals>(vitals);

  // Sync state if props change significantly (e.g. simulation engine updates baseline)
  useEffect(() => {
    lastPropsVitals.current = vitals;
    setLiveVitals(vitals);
  }, [vitals]);

  // Real-time jitter effect
  useEffect(() => {
    const interval = setInterval(() => {
      setLiveVitals(current => {
        const baseline = lastPropsVitals.current;

        // Helper to add constrained random noise
        const jitter = (val: number, factor: number) => {
          const noise = (Math.random() - 0.5) * factor;
          // Stay within a small range of baseline to avoid drifting too far
          const result = val + noise;
          const diff = result - baseline[Object.keys(baseline).find(key => baseline[key as keyof Vitals] === val) as keyof Vitals] as number;

          if (Math.abs(diff) > factor) {
             return val + (diff > 0 ? -0.1 : 0.1); // Gently push back to baseline
          }
          return result;
        };

        return {
          ...current,
          hr: Math.round(jitter(current.hr, 2)),
          // BP fluctuates less frequently/randomly in reality but we can simulate minor NIBP variability if we want
          // usually NIBP is static until next cycle, but for "vibe" we can keep it as is or tiny drift
          rr: Math.round(jitter(current.rr, 1.5)),
          o2: Math.min(100, Math.max(0, Math.round(jitter(current.o2, 0.8)))),
          temp: parseFloat(jitter(current.temp, 0.05).toFixed(1))
        };
      });
    }, 1500); // Update every 1.5s for realistic "drift"

    return () => clearInterval(interval);
  }, []);

  // Color logic based on clinical thresholds
  const getHrColor = (hr: number) => hr > 110 || hr < 55 ? 'text-red-500' : 'text-emerald-500';
  const getO2Color = (o2: number) => o2 < 93 ? 'text-red-500' : 'text-blue-400';
  const getBpColor = (sys: number) => sys < 95 || sys > 160 ? 'text-red-500' : 'text-yellow-400';

  return (
    <div className="bg-slate-900 border-b border-slate-700/50 p-3 shadow-2xl sticky top-0 z-30 backdrop-blur-xl">
      <div className="max-w-5xl mx-auto">
        <div className="flex items-center justify-between mb-2">
           <div className="flex items-center gap-2">
              <div className="w-2 h-2 bg-emerald-500 rounded-full animate-ping"></div>
              <h2 className="text-[10px] uppercase tracking-[0.2em] text-slate-400 font-bold">Bedside Monitor — Bed 04</h2>
           </div>
           <div className="flex items-center gap-4">
              <span className="text-[10px] text-slate-500 font-mono">SWEEP SPEED: 25mm/s</span>
              <span className="text-[10px] text-emerald-500/80 font-mono font-bold tracking-tighter bg-emerald-500/10 px-2 py-0.5 rounded border border-emerald-500/20">
                TELEMETRY ACTIVE
              </span>
           </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
          <VitalBox 
            label="ECG/HR" 
            value={liveVitals.hr} 
            unit="bpm" 
            color={getHrColor(liveVitals.hr)} 
            flicker={liveVitals.hr > 120}
          />
          <VitalBox 
            label="NIBP" 
            value={`${liveVitals.bpSystolic}/${liveVitals.bpDiastolic}`} 
            unit="mmHg" 
            color={getBpColor(liveVitals.bpSystolic)} 
            subValue={`MAP ${Math.round((liveVitals.bpSystolic + 2 * liveVitals.bpDiastolic) / 3)}`}
          />
          <VitalBox 
            label="SpO2" 
            value={liveVitals.o2} 
            unit="%" 
            color={getO2Color(liveVitals.o2)} 
          />
          <VitalBox 
            label="Resp" 
            value={liveVitals.rr} 
            unit="brpm" 
            color="text-cyan-400" 
          />
          <VitalBox 
            label="Temp" 
            value={liveVitals.temp.toFixed(1)} 
            unit="°C" 
            color="text-orange-400" 
          />
        </div>

        <div className="mt-2 flex justify-between items-center border-t border-slate-800/50 pt-2">
             <div className="flex gap-4">
                <span className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">Alarms: Enabled</span>
                <span className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">Lead: II</span>
             </div>
             <span className={`text-[11px] font-bold tracking-widest uppercase monitor-font animate-pulse ${getHrColor(liveVitals.hr)}`}>
                {vitals.rhythm}
             </span>
        </div>
      </div>
    </div>
  );
};

