import React, { useState, useRef } from 'react';
import { ImageSize } from '../types';

interface Props {
  onAction: (action: string) => void;
  onRecord: (blob: Blob) => void;
  onLiveToggle: () => void;
  isLiveActive: boolean;
  imageSize: ImageSize;
  onImageSizeChange: (size: ImageSize) => void;
  disabled: boolean;
}

const CATEGORIES = [
  { id: 'history', label: 'History', icon: '📋' },
  { id: 'exam', label: 'Physical Exam', icon: '🩺' },
  { id: 'orders', label: 'Orders/Labs', icon: '🧪' },
  { id: 'imaging', label: 'Imaging', icon: '☢️' },
  { id: 'treatment', label: 'Treatment', icon: '💊' },
  { id: 'consult', label: 'Consult', icon: '☎️' },
];

const QUICK_ORDERS = {
  Labs: ['CBC', 'CMP', 'Troponin', 'Coags', 'UA', 'D-Dimer', 'Type & Screen'],
  Meds: ['Morphine 4mg IV', 'Zofran 4mg IV', 'Toradol 30mg IV', 'Fentanyl 50mcg IV', 'Aspirin 324mg PO', 'Nitro 0.4mg SL'],
  Fluids: ['1L NS Bolus', '500mL NS Bolus', 'LR @ 100cc/hr'],
  Imaging: ['CXR (Portable)', 'CT Head (Non-con)', 'CT A/P (w/ Contrast)', 'EKG', 'U/S FAST Exam']
};

const Controls: React.FC<Props> = ({ 
  onAction, onRecord, onLiveToggle, isLiveActive, imageSize, onImageSizeChange, disabled 
}) => {
  const [activeCategory, setActiveCategory] = useState<string | null>(null);
  const [showTSheet, setShowTSheet] = useState(false);
  const [inputText, setInputText] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    const prefix = activeCategory ? `[${CATEGORIES.find(c => c.id === activeCategory)?.label}] ` : '';
    onAction(`${prefix}${inputText}`);
    setInputText('');
    setActiveCategory(null);
  };

  const handleQuickOrder = (order: string, category: string) => {
    onAction(`[${category}] ${order}`);
    setShowTSheet(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      audioChunksRef.current = [];
      recorder.ondataavailable = (e) => audioChunksRef.current.push(e.data);
      recorder.onstop = () => {
        const blob = new Blob(audioChunksRef.current, { type: 'audio/wav' });
        onRecord(blob);
        stream.getTracks().forEach(t => t.stop());
      };
      recorder.start();
      setIsRecording(true);
    } catch (err) { console.error(err); }
  };

  const stopRecording = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
  };

  return (
    <div className="bg-slate-900 border-t border-slate-700 p-4 relative">
      {/* T-Sheet / Quick Orders Panel */}
      {showTSheet && (
        <div className="absolute bottom-full left-0 right-0 mb-2 p-4 bg-slate-800 border-t border-slate-700 shadow-2xl animate-fadeIn z-20 max-h-[60vh] overflow-y-auto rounded-t-xl">
          <div className="max-w-4xl mx-auto">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-sm font-bold text-emerald-400 uppercase tracking-widest flex items-center gap-2">
                <span className="text-lg">📋</span> T-Sheet Quick Orders
              </h3>
              <button onClick={() => setShowTSheet(false)} className="text-slate-500 hover:text-white">✕</button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              {Object.entries(QUICK_ORDERS).map(([category, orders]) => (
                <div key={category}>
                  <h4 className="text-[10px] font-bold text-slate-500 uppercase mb-2 border-b border-slate-700 pb-1">{category}</h4>
                  <div className="flex flex-col gap-1">
                    {orders.map(order => (
                      <button
                        key={order}
                        onClick={() => handleQuickOrder(order, category)}
                        disabled={disabled}
                        className="text-left px-2 py-1.5 text-xs text-slate-300 hover:bg-emerald-600/20 hover:text-emerald-400 rounded transition-colors bg-slate-900/50 border border-slate-700/50"
                      >
                        {order}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <div className="max-w-4xl mx-auto space-y-3">
        <div className="flex flex-wrap items-center justify-between gap-4">
          <div className="flex flex-wrap gap-2">
            <button
              onClick={() => setShowTSheet(!showTSheet)}
              className={`px-3 py-1.5 rounded-full text-xs font-bold flex items-center gap-1.5 transition-all border
                ${showTSheet ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-slate-800 text-emerald-400 border-emerald-900/50'}
              `}
            >
              <span>📋</span> T-Sheet
            </button>
            <div className="w-[1px] h-6 bg-slate-700 mx-1 hidden md:block"></div>
            {CATEGORIES.map((cat) => (
              <button
                key={cat.id}
                onClick={() => setActiveCategory(activeCategory === cat.id ? null : cat.id)}
                disabled={disabled}
                className={`px-3 py-1.5 rounded-full text-xs font-semibold flex items-center gap-1.5 transition-all
                  ${activeCategory === cat.id ? 'bg-emerald-600 text-white' : 'bg-slate-800 text-slate-300'}
                `}
              >
                <span>{cat.icon}</span>{cat.label}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-2 bg-slate-800/50 p-1 rounded-lg border border-slate-700">
             <span className="text-[10px] font-bold text-slate-500 uppercase px-2">IQ:</span>
             {(['1K', '2K', '4K'] as ImageSize[]).map(size => (
               <button 
                 key={size}
                 onClick={() => onImageSizeChange(size)}
                 className={`px-2 py-1 text-[10px] font-bold rounded ${imageSize === size ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-700'}`}
               >
                 {size}
               </button>
             ))}
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={onLiveToggle}
            className={`p-3 rounded-lg flex items-center gap-2 transition-all ${isLiveActive ? 'bg-red-600 text-white animate-pulse' : 'bg-slate-800 text-slate-300 border border-slate-700 hover:bg-slate-700'}`}
            title="Live Conversation Mode"
          >
            <span>🎙️</span>
            <span className="text-xs font-bold uppercase tracking-wider hidden md:block">{isLiveActive ? 'Live Mode Active' : 'Live Voice'}</span>
          </button>

          <form onSubmit={handleSubmit} className="flex-1 relative">
            <input
              type="text"
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              disabled={disabled}
              placeholder={disabled ? 'Processing...' : activeCategory ? `Enter ${CATEGORIES.find(c => c.id === activeCategory)?.label}...` : "Type action..."}
              className="w-full bg-slate-950 text-slate-100 rounded-lg pl-4 pr-12 py-3 border border-slate-700 focus:outline-none focus:ring-1 focus:border-emerald-500 transition-colors font-mono text-sm shadow-inner"
            />
            <button type="submit" disabled={disabled || !inputText.trim()} className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 rounded-md bg-emerald-600 text-white hover:bg-emerald-500 disabled:opacity-0 transition-all">
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4"><path d="M3.105 2.289a.75.75 0 00-.826.95l1.414 4.925A1.5 1.5 0 005.135 9.25h6.115a.75.75 0 010 1.5H5.135a1.5 1.5 0 00-1.442 1.085l-1.414 4.926a.75.75 0 00.826.95 14 14 0 007-7 14 14 0 00-7-7z" /></svg>
            </button>
          </form>

          <button 
            onMouseDown={startRecording}
            onMouseUp={stopRecording}
            onMouseLeave={isRecording ? stopRecording : undefined}
            className={`p-3 rounded-lg transition-all ${isRecording ? 'bg-orange-600 text-white scale-110 shadow-[0_0_15px_rgba(234,88,12,0.4)]' : 'bg-slate-800 text-slate-300 border border-slate-700 hover:bg-slate-700'}`}
            title="Hold to Transcribe Action"
          >
            <span className={isRecording ? 'animate-ping inline-block' : ''}>🎤</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export default Controls;

import React, { useState, useRef, useEffect } from 'react';
import { GameState, Message, ImageSize } from './types';
import { analyzePDFAndStartCase, progressSimulation, generateMedicalImage, transcribeAudio, decode, decodeAudioData, encode } from './services/geminiService';
import { GoogleGenAI, Modality } from '@google/genai';
import VitalsMonitor from './components/VitalsMonitor';
import ChatInterface from './components/ChatInterface';
import Controls from './components/Controls';
import DebriefScreen from './components/DebriefScreen';

const SAVE_KEY = 'medisim_er_save_state';

const App: React.FC = () => {
  // Initialize state from localStorage if available
  const [gameState, setGameState] = useState<GameState>(() => {
    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Basic validation: Ensure stage is one of the expected values
        if (['upload', 'analyzing', 'playing', 'debrief'].includes(parsed.stage)) {
          return parsed;
        }
      } catch (e) {
        console.error("Failed to recover saved state:", e);
      }
    }
    return {
      stage: 'upload',
      vitals: { hr: 0, bpSystolic: 0, bpDiastolic: 0, rr: 0, o2: 0, temp: 0, rhythm: '--' },
      messages: [],
      learningPoints: [],
      hiddenDiagnosis: '',
      caseContext: '',
      imageSize: '1K',
    };
  });

  const [isLoading, setIsLoading] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [isLiveActive, setIsLiveActive] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const liveSessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Auto-save effect: Persist state to localStorage on every change
  useEffect(() => {
    if (gameState.stage !== 'upload') {
      localStorage.setItem(SAVE_KEY, JSON.stringify(gameState));
    }
  }, [gameState]);

  useEffect(() => {
    return () => {
      if (liveSessionRef.current) liveSessionRef.current.close();
      if (audioContextRef.current) audioContextRef.current.close();
    };
  }, []);

  const startNewCase = () => {
    localStorage.removeItem(SAVE_KEY);
    window.location.reload();
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.type !== 'application/pdf') {
      setError("Please upload a PDF file.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setGameState(prev => ({ ...prev, stage: 'analyzing' }));

    try {
      const reader = new FileReader();
      reader.onload = async (e) => {
        const base64Data = (e.target?.result as string).split(',')[1];
        try {
          const initData = await analyzePDFAndStartCase(base64Data);
          setGameState(prev => ({
            ...prev,
            stage: 'playing',
            vitals: initData.vitals,
            messages: [{
              role: 'assistant',
              content: initData.intro,
              timestamp: Date.now()
            }],
            learningPoints: initData.learningPoints,
            hiddenDiagnosis: initData.diagnosis,
            caseContext: initData.context
          }));
        } catch (err) {
          setError("Failed to analyze PDF. Try again.");
          setGameState(prev => ({ ...prev, stage: 'upload' }));
        } finally {
            setIsLoading(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError("Error reading file.");
      setIsLoading(false);
      setGameState(prev => ({ ...prev, stage: 'upload' }));
    }
  };

  const handleUserAction = async (actionText: string) => {
    const userMsg: Message = { role: 'user', content: actionText, timestamp: Date.now() };
    setGameState(prev => ({ ...prev, messages: [...prev.messages, userMsg] }));
    setIsLoading(true);

    try {
      const history = gameState.messages.concat(userMsg).map(m => `${m.role.toUpperCase()}: ${m.content}`);
      const response = await progressSimulation(gameState.caseContext, history, actionText);

      let imageData = undefined;
      if (response.visualRequest) {
        try {
          const base64Img = await generateMedicalImage(response.visualRequest.description, response.visualRequest.type, gameState.imageSize);
          if (base64Img) imageData = base64Img;
        } catch (imgErr) { console.error(imgErr); }
      }

      const sysMsg: Message = {
        role: 'assistant',
        content: response.narrative,
        timestamp: Date.now(),
        type: response.updatedVitals.hr < 50 || response.updatedVitals.hr > 140 ? 'alert' : 'text',
        imageData
      };

      if (response.isCaseOver && response.debriefData) {
        setGameState(prev => ({
          ...prev,
          vitals: response.updatedVitals,
          messages: [...prev.messages, userMsg, sysMsg],
          debriefData: response.debriefData,
          stage: 'debrief'
        }));
      } else {
        setGameState(prev => ({
          ...prev,
          vitals: response.updatedVitals,
          messages: [...prev.messages, userMsg, sysMsg]
        }));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const startLiveConversation = async () => {
    if (isLiveActive) {
      liveSessionRef.current?.close();
      setIsLiveActive(false);
      return;
    }

    try {
      if (!(await (window as any).aistudio.hasSelectedApiKey())) {
        await (window as any).aistudio.openSelectKey();
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = outCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            const source = inCtx.createMediaStreamSource(stream);
            const processor = inCtx.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const blob = { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' };
              sessionPromise.then(s => s.sendRealtimeInput({ media: blob }));
            };
            source.connect(processor);
            processor.connect(inCtx.destination);
            setIsLiveActive(true);
          },
          onmessage: async (msg) => {
            const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }
            if (msg.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onclose: () => setIsLiveActive(false),
          onerror: () => setIsLiveActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
          systemInstruction: `You are part of an ER simulation. Act as the patient, a nurse, or a consultant. Talk naturally and react to clinical decisions based on context: ${gameState.caseContext}. The current history is: ${gameState.messages.map(m=>m.content).join('\n')}`
        }
      });
      liveSessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Live API Error", err);
    }
  };

  const handleTranscription = async (blob: Blob) => {
    setIsTranscribing(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const text = await transcribeAudio(base64);
        if (text) handleUserAction(text);
        setIsTranscribing(false);
      };
      reader.readAsDataURL(blob);
    } catch (err) {
      setIsTranscribing(false);
    }
  };

  const renderContent = () => {
    switch (gameState.stage) {
      case 'upload':
      case 'analyzing':
        return (
          <div className="flex-1 flex flex-col items-center justify-center p-6 text-center animate-fadeIn">
            <div className="max-w-md w-full bg-slate-800/50 p-8 rounded-2xl border border-slate-700 shadow-2xl backdrop-blur-sm">
              <div className="mb-6 text-6xl">🩺</div>
              <h2 className="text-2xl font-bold text-white mb-2">Upload CME Material</h2>
              <p className="text-slate-400 mb-8">Upload a PDF guideline to generate a case.</p>
              {gameState.stage === 'analyzing' ? (
                   <div className="flex flex-col items-center gap-4">
                      <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                      <p className="text-emerald-400 font-mono text-sm animate-pulse">Analyzing...</p>
                   </div>
              ) : (
                  <div className="relative group cursor-pointer">
                      <input type="file" accept="application/pdf" onChange={handleFileUpload} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"/>
                      <div className="border-2 border-dashed border-slate-600 rounded-xl p-6 group-hover:border-emerald-500 transition-all">
                          Browse PDF
                      </div>
                  </div>
              )}
              {error && <div className="mt-4 p-3 bg-red-900/30 border border-red-800 rounded text-red-200 text-sm">{error}</div>}
            </div>
          </div>
        );
      case 'debrief':
        return gameState.debriefData ? <DebriefScreen data={gameState.debriefData} onRestart={startNewCase} /> : null;
      default:
        return (
          <div className="flex-1 flex flex-col overflow-hidden relative">
              <VitalsMonitor vitals={gameState.vitals} />
              <div className="flex-1 overflow-hidden relative flex flex-col">
                  <ChatInterface messages={gameState.messages} isLoading={isLoading || isTranscribing} />
              </div>
              <Controls 
                  onAction={handleUserAction} 
                  onRecord={handleTranscription}
                  onLiveToggle={startLiveConversation}
                  isLiveActive={isLiveActive}
                  imageSize={gameState.imageSize}
                  onImageSizeChange={(size) => setGameState(p => ({ ...p, imageSize: size }))}
                  disabled={isLoading} 
              />
          </div>
        );
    }
  };

  return (
    <div className="h-screen flex flex-col bg-slate-900 text-slate-200 overflow-hidden">
      <header className="p-4 bg-slate-950 border-b border-slate-800 flex justify-between items-center z-10">
        <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-emerald-600 rounded flex items-center justify-center font-bold text-white">M</div>
            <h1 className="text-xl font-bold tracking-tight text-slate-100">MediSim <span className="text-slate-500 font-normal">| ER AI</span></h1>
        </div>
        {gameState.stage !== 'upload' && (
