              <p className="text-slate-400 mb-8">Upload a PDF guideline to generate a case.</p>
              {gameState.stage === 'analyzing' ? (
                   <div className="flex flex-col items-center gap-4">
                      <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                      <p className="text-emerald-400 font-mono text-sm animate-pulse">Analyzing...</p>
                   </div>
              ) : (
                  <div className="relative group cursor-pointer">
                      <input type="file" accept="application/pdf" onChange={handleFileUpload} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"/>
                      <div className="border-2 border-dashed border-slate-600 rounded-xl p-6 group-hover:border-emerald-500 transition-all">
                          Browse PDF
                      </div>
                  </div>
              )}
              {error && <div className="mt-4 p-3 bg-red-900/30 border border-red-800 rounded text-red-200 text-sm">{error}</div>}
            </div>
          </div>
        );
      case 'debrief':
        return gameState.debriefData ? <DebriefScreen data={gameState.debriefData} onRestart={startNewCase} /> : null;
      default:
        return (
          <div className="flex-1 flex flex-col overflow-hidden relative">
              <VitalsMonitor vitals={gameState.vitals} />
              <div className="flex-1 overflow-hidden relative flex flex-col">
                  <ChatInterface messages={gameState.messages} isLoading={isLoading} />
              </div>
              <Controls 
                  onAction={handleUserAction} 
                  disabled={isLoading} 
              />
              {error && (
                <div className="absolute bottom-4 left-1/2 -translate-x-1/2 p-3 bg-red-700 text-white rounded-lg shadow-lg z-50 animate-fadeIn">
                  <p className="text-sm font-semibold">{error}</p>
                  <button onClick={() => setError(null)} className="ml-3 text-xs opacity-70 hover:opacity-100">Dismiss</button>
                </div>
              )}
          </div>
        );
    }
  };

  return (
    <div className="h-screen flex flex-col bg-slate-900 text-slate-200 overflow-hidden relative">
      <header className="p-4 bg-slate-950 border-b border-slate-800 flex justify-between items-center z-10">
        <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-emerald-600 rounded flex items-center justify-center font-bold text-white">M</div>
            <h1 className="text-xl font-bold tracking-tight text-slate-100">MediSim <span className="text-slate-500 font-normal">| ER AI</span></h1>
        </div>
        {gameState.stage !== 'upload' && (
             <button onClick={startNewCase} className="text-xs text-slate-400 hover:text-white underline">New Case</button>
        )}
      </header>
      {renderContent()}
    </div>
  );
};

export default App;

