import { GoogleGenAI, Type } from "@google/genai";
import { Vitals, SimulationResponse } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const TEXT_MODEL = "gemini-3-pro-preview"; 

export const analyzePDFAndStartCase = async (
  pdfBase64: string
): Promise<{ 
  intro: string; 
  vitals: Vitals; 
  context: string; 
  learningPoints: string[]; 
  diagnosis: string 
}> => {
  const ai = getAI();
  const prompt = `
    You are a senior Emergency Medicine Attending and Clinical Educator.

    TASK:
    1. Analyze the attached CME (Continuing Medical Education) PDF document.
    2. Identify the core clinical topic, critical pitfalls, and major learning points.
    3. Generate a HIGH-STAKES, COMPLEX clinical simulation case based on this document.
    4. The case should start with a patient presentation in the ER.

    CRITICAL CONSTRAINT:
    - The 'context' field MUST be a concise summary (max 200 words) of the clinical logic.
    - Do NOT reproduce large sections of the PDF text in the output.
    - Ensure valid JSON output.

    OUTPUT FORMAT (JSON):
    {
      "intro": "The initial scene description and patient presentation (Chief Complaint, appearance).",
      "vitals": {
        "hr": 90, "bpSystolic": 120, "bpDiastolic": 80, "rr": 16, "o2": 98, "temp": 37.0, "rhythm": "Sinus Rhythm"
      },
      "context": "A concise summary of the case logic and how it relates to the PDF.",
      "learningPoints": ["Point 1", "Point 2"],
      "diagnosis": "The final diagnosis based on the PDF content."
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: TEXT_MODEL,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "application/pdf",
              data: pdfBase64,
            },
          },
          { text: prompt },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            intro: { type: Type.STRING },
            vitals: {
              type: Type.OBJECT,
              properties: {
                hr: { type: Type.NUMBER },
                bpSystolic: { type: Type.NUMBER },
                bpDiastolic: { type: Type.NUMBER },
                rr: { type: Type.NUMBER },
                o2: { type: Type.NUMBER },
                temp: { type: Type.NUMBER },
                rhythm: { type: Type.STRING },
              },
              required: ["hr", "bpSystolic", "bpDiastolic", "rr", "o2", "temp", "rhythm"],
            },
            context: { 
                type: Type.STRING,
                description: "Concise summary of case logic (max 200 words)" 
            },
            learningPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
            diagnosis: { type: Type.STRING },
          },
        },
      },
    });

    if (!response.text) {
      console.error("Gemini API returned no text in analyzePDFAndStartCase.", { fullResponse: response });
      throw new Error("No text response from Gemini API when starting case.");
    }

    let cleanText = response.text.trim();
    if (cleanText.startsWith("```")) {
        cleanText = cleanText.replace(/^```(json)?/, "").replace(/```$/, "").trim();
    }

    try {
      return JSON.parse(cleanText);
    } catch (parseError: any) {
      console.error("JSON parsing error in analyzePDFAndStartCase:", parseError.message);
      console.log("Raw response text from Gemini (analyzePDFAndStartCase):", cleanText);
      throw new Error(`Failed to parse AI response for case start: ${parseError.message}`);
    }
  } catch (error) {
    console.error("Error starting case:", error);
    throw error;
  }
};

export const progressSimulation = async (
  context: string,
  history: string[],
  userAction: string
): Promise<SimulationResponse> => {
  const ai = getAI();
  const prompt = `
    You are the simulation engine for an ER case based on a CME document.

    CASE CONTEXT: ${context}

    HISTORY:
    ${history.join("\n")}

    USER ACTION: ${userAction}

    INSTRUCTIONS:
    1. React to the user's action realistically. Time moves forward.
    2. Update vital signs based on the patient's trajectory.
    3. If the case is concluded, set isCaseOver to true and populate debriefData.

    OUTPUT FORMAT (JSON):
    {
      "narrative": "Result of the action.",
      "updatedVitals": { ... },
      "isCaseOver": boolean,
      "debriefData": { ... } (OPTIONAL)
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: TEXT_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
         responseSchema: {
          type: Type.OBJECT,
          properties: {
            narrative: { type: Type.STRING },
            updatedVitals: {
              type: Type.OBJECT,
              properties: {
                hr: { type: Type.NUMBER },
                bpSystolic: { type: Type.NUMBER },
                bpDiastolic: { type: Type.NUMBER },
                rr: { type: Type.NUMBER },
                o2: { type: Type.NUMBER },
                temp: { type: Type.NUMBER },
                rhythm: { type: Type.STRING },
              },
              required: ["hr", "bpSystolic", "bpDiastolic", "rr", "o2", "temp", "rhythm"],
            },
            isCaseOver: { type: Type.BOOLEAN },
            debriefData: {
              type: Type.OBJECT,
              properties: {
                outcome: { type: Type.STRING },
                score: { type: Type.INTEGER },
                summary: { type: Type.STRING },
                performanceBreakdown: {
                    type: Type.OBJECT,
                    properties: {
                        historyDataCollection: { type: Type.INTEGER },
                        differentialDiagnosis: { type: Type.INTEGER },
                        medicalManagement: { type: Type.INTEGER },
                        communicationEfficiency: { type: Type.INTEGER },
                    },
                    required: ["historyDataCollection", "differentialDiagnosis", "medicalManagement", "communicationEfficiency"]
                },
                criticalEvents: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      event: { type: Type.STRING },
                      userAction: { type: Type.STRING },
                      optimalAction: { type: Type.STRING },
                      feedback: { type: Type.STRING },
                      type: { type: Type.STRING, enum: ["positive", "negative", "neutral"] }
                    },
                    required: ["event", "userAction", "optimalAction", "feedback", "type"]
                  }
                },
                missedOpportunities: { type: Type.ARRAY, items: { type: Type.STRING } },
                cmeLearningPoints: { type: Type.ARRAY, items: { type: Type.STRING } }
              }
            }
          },
        },
      },
    });

    if (!response.text) {
      console.error("Gemini API returned no text in progressSimulation.", { fullResponse: response });
      throw new Error("No text response from Gemini API during simulation progress.");
    }
    let cleanText = response.text.trim();
    if (cleanText.startsWith("```")) {
        cleanText = cleanText.replace(/^```(json)?/, "").replace(/```$/, "").trim();
    }

    console.log("Raw response text from Gemini (progressSimulation):", cleanText); // Add this for debugging

    try {
      return JSON.parse(cleanText);
    } catch (parseError: any) {
      console.error("JSON parsing error in progressSimulation:", parseError.message);
      console.log("Raw text that failed parsing (progressSimulation):", cleanText);
      throw new Error(`Failed to parse AI response for simulation progress: ${parseError.message}`);
    }
  } catch (error) {
    console.error("Error progressing simulation:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { GameState, Message } from './types';
import { analyzePDFAndStartCase, progressSimulation } from './services/geminiService';
import VitalsMonitor from './components/VitalsMonitor';
import ChatInterface from './components/ChatInterface';
import Controls from './components/Controls';
import DebriefScreen from './components/DebriefScreen';
import ErrorModal from './components/ErrorModal'; // Import the new ErrorModal

const SAVE_KEY = 'medisim_er_save_state';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(() => {
    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (['upload', 'analyzing', 'playing', 'debrief'].includes(parsed.stage)) {
          return parsed;
        }
      } catch (e) {
        console.error("Failed to recover saved state:", e);
      }
    }
    return {
      stage: 'upload',
      vitals: { hr: 0, bpSystolic: 0, bpDiastolic: 0, rr: 0, o2: 0, temp: 0, rhythm: '--' },
      messages: [],
      learningPoints: [],
      hiddenDiagnosis: '',
      caseContext: '',
    };
  });

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null); // Use this for the ErrorModal

  useEffect(() => {
    if (gameState.stage !== 'upload') {
      localStorage.setItem(SAVE_KEY, JSON.stringify(gameState));
    }
  }, [gameState]);

  const startNewCase = () => {
    localStorage.removeItem(SAVE_KEY);
    window.location.reload();
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.type !== 'application/pdf') {
      setError("Please upload a PDF file.");
      return;
    }

    setIsLoading(true);
    setError(null); // Clear previous errors
    setGameState(prev => ({ ...prev, stage: 'analyzing' }));

    try {
      const reader = new FileReader();
      reader.onload = async (e) => {
        const base64Data = (e.target?.result as string).split(',')[1];
        try {
          const initData = await analyzePDFAndStartCase(base64Data);
          setGameState(prev => ({
            ...prev,
            stage: 'playing',
            vitals: initData.vitals,
            messages: [{
              role: 'assistant',
              content: initData.intro,
              timestamp: Date.now()
            }],
            learningPoints: initData.learningPoints,
            hiddenDiagnosis: initData.diagnosis,
            caseContext: initData.context
          }));
        } catch (err: any) {
          console.error("Error analyzing PDF:", err); // Log full error object
          setError(`Failed to analyze PDF: ${err.message || err.toString()}. Please ensure the document is valid and try again.`);
          setGameState(prev => ({ ...prev, stage: 'upload' }));
        } finally {
            setIsLoading(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err: any) {
      console.error("Error reading file:", err); // Log full error object
      setError(`Error reading file: ${err.message || err.toString()}.`);
      setIsLoading(false);
      setGameState(prev => ({ ...prev, stage: 'upload' }));
    }
  };

  const handleUserAction = async (actionText: string) => {
    const userMsg: Message = { role: 'user', content: actionText, timestamp: Date.now() };
    setGameState(prev => ({ ...prev, messages: [...prev.messages, userMsg] }));
    setIsLoading(true);
    setError(null); // Clear previous errors

    try {
      const history = gameState.messages.concat(userMsg).map(m => `${m.role.toUpperCase()}: ${m.content}`);
      const response = await progressSimulation(gameState.caseContext, history, actionText);

      const sysMsg: Message = {
        role: 'assistant',
        content: response.narrative,
        timestamp: Date.now(),
        type: response.updatedVitals.hr < 50 || response.updatedVitals.hr > 140 ? 'alert' : 'text',
      };

      if (response.isCaseOver && response.debriefData) {
        setGameState(prev => ({
          ...prev,
          vitals: response.updatedVitals,
          messages: [...prev.messages, userMsg, sysMsg],
          debriefData: response.debriefData,
          stage: 'debrief'
        }));
      } else {
        setGameState(prev => ({
          ...prev,
          vitals: response.updatedVitals,
          messages: [...prev.messages, userMsg, sysMsg]
        }));
      }
    } catch (err: any) {
      console.error("Error during simulation progress:", err); // Log full error object
      setError(`Simulation encountered a critical error: ${err.message || err.toString()}. The simulation cannot continue.`);
    } finally {
      setIsLoading(false);
    }
  };

  const clearError = () => {
    setError(null);
  };

  const renderContent = () => {
    switch (gameState.stage) {
      case 'upload':
      case 'analyzing':
        return (
          <div className="flex-1 flex flex-col items-center justify-center p-6 text-center animate-fadeIn">
            <div className="max-w-md w-full bg-slate-800/50 p-8 rounded-2xl border border-slate-700 shadow-2xl backdrop-blur-sm">
              <div className="mb-6 text-6xl">🩺</div>
              <h2 className="text-2xl font-bold text-white mb-2">Upload CME Material</h2>
              <p className="text-slate-400 mb-8">Upload a PDF guideline to generate a case.</p>
              {gameState.stage === 'analyzing' ? (
                   <div className="flex flex-col items-center gap-4">
                      <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                      <p className="text-emerald-400 font-mono text-sm animate-pulse">Analyzing...</p>
                   </div>
              ) : (
                  <div className="relative group cursor-pointer">
                      <input type="file" accept="application/pdf" onChange={handleFileUpload} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"/>
                      <div className="border-2 border-dashed border-slate-600 rounded-xl p-6 group-hover:border-emerald-500 transition-all">
                          Browse PDF
                      </div>
                  </div>
              )}
            </div>
          </div>
        );
      case 'debrief':
        return gameState.debriefData ? <DebriefScreen data={gameState.debriefData} onRestart={startNewCase} /> : null;
      default:
        return (
          <div className="flex-1 flex flex-col overflow-hidden relative">
              <VitalsMonitor vitals={gameState.vitals} />
              <div className="flex-1 overflow-hidden relative flex flex-col">
                  <ChatInterface messages={gameState.messages} isLoading={isLoading} />
              </div>
              <Controls 
                  onAction={handleUserAction} 
                  disabled={isLoading} 
              />
          </div>
        );
    }
  };

  return (
    <div className="h-screen flex flex-col bg-slate-900 text-slate-200 overflow-hidden relative">
      <header className="p-4 bg-slate-950 border-b border-slate-800 flex justify-between items-center z-10">
        <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-emerald-600 rounded flex items-center justify-center font-bold text-white">M</div>
            <h1 className="text-xl font-bold tracking-tight text-slate-100">MediSim <span className="text-slate-500 font-normal">| ER AI</span></h1>
        </div>
        {gameState.stage !== 'upload' && (
             <button onClick={startNewCase} className="text-xs text-slate-400 hover:text-white underline">New Case</button>
        )}
      </header>
      {renderContent()}
      {error && <ErrorModal message={error} onDismiss={clearError} />} {/* Display the error modal */}
    </div>
  );
};

export default App;
